        {
          "id": "01f101e256ea1a699083737a0cd751cf",
          "sql": [
            "date_trunc('week', date_add(ftd_funnel_fr.FirstTimeDeposit_DateTime, 1)) - interval 1 day\r\n"
          ],
          "display_name": "week_start_sunday",
          "instruction": [
            "Start date of the week using a Sunday–Saturday convention, derived from FirstTimeDeposit_DateTime.\n",
            "This dimension shifts the date by one day before applying date_trunc('week') to override the default Monday-based behavior and always returns a Sunday date.\n",
            "Must be used for all weekly aggregations and groupings related to First Time Deposits."
          ]
        }
